document.addEventListener("DOMContentLoaded",(()=>{async function handleFormSubmit(e){e.preventDefault();const t=e.currentTarget,o=t.getAttribute("data-url"),n=t.getAttribute("data-message"),a=t.getAttribute("data-field-key"),s=document.getElementById(a);if(!s)return void console.error("The element with the specified ID was not found.");const l=`${o}/${s.value}`,r={},c=[];document.querySelectorAll(".card-body").forEach((e=>{e.querySelectorAll("input, select, textarea").forEach((e=>{if("INPUT"===e.tagName)if("checkbox"===e.type)r[e.name]=e.checked;else if("file"===e.type&&e.files.length>0){const t=new Promise(((t,o)=>{const n=new FileReader;n.onload=function(o){r[e.name]=o.target.result,t()},n.onerror=o,n.readAsDataURL(e.files[0])}));c.push(t)}else r[e.name]=e.value;else if("TEXTAREA"===e.tagName)r[e.name]=e.value;else if("SELECT"===e.tagName)if(e.multiple){const t=Array.from(e.selectedOptions).map((e=>e.value));r[e.name]=t}else r[e.name]=-1===e.selectedIndex?null:e.options[e.selectedIndex].value}))}));try{await Promise.all(c);const e=await fetch(l,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(r)});if(!e.ok)throw new Error(`HTTP error! status: ${e.status}`);const t=await e.json();t.success&&Swal.fire({icon:"success",title:" ",html:`<ul><li class="fw600">${n}</li></ul>`,timer:3e3,confirmButtonText:"Κλείσιμο",customClass:{confirmButton:"class-success custom-confirm-button custom-swal-button",title:"custom-title"}}).then((()=>{window.location.href=t.redirectUrl}))}catch(e){console.error("Σφάλμα:",e)}}document.querySelectorAll(".submitButton").forEach((e=>{e.addEventListener("click",handleFormSubmit)}))}));